from typing import List

class Solution:
    def missingInteger(self, nums: List[int]) -> int:
        # Find longest sequential prefix
        s = nums[0]
        cur = nums[0]
        for i in range(1, len(nums)):
            if nums[i] == cur + 1:
                cur = nums[i]
                s += cur
            else:
                break

        # Smallest integer >= sum s that is missing from nums
        present = set(nums)
        x = s
        while x in present:
            x += 1
        return x
```

