from typing import List

class Solution:
    def missingInteger(self, nums: List[int]) -> int:
        n = len(nums)

        # Find the longest sequential prefix where nums[j] = nums[j-1] + 1
        prefix_sum = nums[0]
        for j in range(1, n):
            if nums[j] == nums[j - 1] + 1:
                prefix_sum += nums[j]
            else:
                break

        # Smallest missing integer >= prefix_sum
        s = set(nums)
        x = prefix_sum
        while x in s:
            x += 1
        return x
